module tb_trojan_2;

  // DUT signals
  reg         clk;
  reg         reset_n;
  reg         cs;
  reg         we;
  reg  [7:0]  address;
  reg  [31:0] write_data;
  wire [31:0] read_data;

  // Instantiate DUT
  aes dut (
    .clk        (clk),
    .reset_n    (reset_n),
    .cs         (cs),
    .we         (we),
    .address    (address),
    .write_data (write_data),
    .read_data  (read_data)
  );

  // Clock generation
  initial clk = 0;
  always #5 clk = ~clk;

  // Write task
  task write_word;
    input [7:0]  addr;
    input [31:0] data;
    begin
      cs         = 1;
      we         = 1;
      address    = addr;
      write_data = data;
      #20;
      cs         = 0;
      we         = 0;
      #10;
    end
  endtask

  // Read task
  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      cs         = 1;
      we         = 0;
      address    = addr;
      write_data = 32'h0;
      #20;
      data = read_data;
      cs   = 0;
      #10;
    end
  endtask

  // AES-128 encrypt task
  task aes128_encrypt;
    input  [127:0] key;
    input  [127:0] plaintext;
    output [127:0] result;
    reg [31:0] rw0, rw1, rw2, rw3;
    begin
      // Write 128-bit key (MSB first), zero-pad upper words
      write_word(8'h10, key[127:96]);
      write_word(8'h11, key[95:64]);
      write_word(8'h12, key[63:32]);
      write_word(8'h13, key[31:0]);
      write_word(8'h14, 32'h0);
      write_word(8'h15, 32'h0);
      write_word(8'h16, 32'h0);
      write_word(8'h17, 32'h0);
      // CONFIG: 128-bit key
      write_word(8'h0a, 32'h0);
      // CTRL: INIT
      write_word(8'h08, 32'h1);
      #2000;
      // Write plaintext
      write_word(8'h20, plaintext[127:96]);
      write_word(8'h21, plaintext[95:64]);
      write_word(8'h22, plaintext[63:32]);
      write_word(8'h23, plaintext[31:0]);
      // CONFIG: encrypt
      write_word(8'h0a, 32'h1);
      // CTRL: NEXT
      write_word(8'h08, 32'h2);
      #2000;
      // Read result
      read_word(8'h30, rw0);
      read_word(8'h31, rw1);
      read_word(8'h32, rw2);
      read_word(8'h33, rw3);
      result = {rw0, rw1, rw2, rw3};
    end
  endtask

  integer i;
  reg [127:0] result;
  reg [127:0] expected;
  reg [127:0] trojan_key;
  reg [127:0] trojan_plain;
  reg [127:0] trojan_result;
  reg [31:0]  tmp;

  initial begin
    // Initialize
    cs         = 0;
    we         = 0;
    address    = 8'h0;
    write_data = 32'h0;
    reset_n    = 0;
    #50;
    reset_n = 1;
    #20;

    // ----------------------------------------------------------------
