    write_word(8'h10, trojan_key[127:96]);
    write_word(8'h11, trojan_key[95:64]);
    write_word(8'h12, trojan_key[63:32]);
    write_word(8'h13, trojan_key[31:0]);   // == 32'hCAFEBABE
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);
    // CONFIG: 128-bit key
    write_word(8'h0a, 32'h0);
    // CTRL: INIT — this samples key[31:0] == CAFEBABE and sets corrupt_reg
    write_word(8'h08, 32'h1);
    #2000;

    $display("TROJAN_TRIGGERED");

    // Encrypt a block to observe the corrupted output
    write_word(8'h20, trojan_plain[127:96]);
    write_word(8'h21, trojan_plain[95:64]);
    write_word(8'h22, trojan_plain[63:32]);
    write_word(8'h23, trojan_plain[31:0]);
    // CONFIG: encrypt
    write_word(8'h0a, 32'h1);
    // CTRL: NEXT
    write_word(8'h08, 32'h2);
    #2000;

    // Read trojan result (bits[7:0] should be inverted)
    read_word(8'h30, tmp); trojan_result[127:96] = tmp;
    read_word(8'h31, tmp); trojan_result[95:64]  = tmp;
    read_word(8'h32, tmp); trojan_result[63:32]  = tmp;
    read_word(8'h33, tmp); trojan_result[31:0]   = tmp;

    $display("TROJAN_RESULT: %h", trojan_result);

    // ----------------------------------------------------------------
    $display("TEST_COMPLETE");
    $finish;
  end

endmodule
